@implements IDisposable
@inject NotificationHub Hub
@rendermode InteractiveServer

<span class="notification-bell" @onclick="Toggle">
    🔔
    @if (_unread > 0)
    {
        <span class="badge bg-danger rounded-pill">@_unread</span>
    }
</span>

@code {
    private int _unread;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _unread = Hub.GetUnreadCount();
        _handler = () => InvokeAsync(() =>
        {
            _unread = Hub.GetUnreadCount();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void Toggle() { }

    public void Dispose() => Hub.OnChange -= _handler;
}

.notification-bell {
    position: relative;
    cursor: pointer;
    font-size: 1.4rem;
    padding: 0.25rem 0.5rem;
}

.notification-bell .badge {
    position: absolute;
    top: -4px;
    right: -4px;
    font-size: 0.65rem;
    padding: 0.2em 0.45em;
}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h3>Notifications</h3>

<button class="btn btn-sm btn-outline-secondary mb-3" @onclick="Hub.MarkAllRead">
    Mark All Read
</button>

@if (!_notifications.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    @foreach (var group in _notifications.GroupBy(n => n.Severity).OrderBy(g => g.Key))
    {
        <h5 class="mt-3">@group.Key</h5>
        <ul class="list-group mb-2">
            @foreach (var n in group.OrderByDescending(x => x.Timestamp))
            {
                <li class="list-group-item d-flex justify-content-between align-items-start @(n.IsRead ? "" : "list-group-item-warning")">
                    <div>
                        <strong>@n.Title</strong><br />
                        <small>@n.Message</small><br />
                        <small class="text-muted">@n.Timestamp.ToString("g")</small>
                    </div>
                    <div>
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => Hub.MarkAsRead(n.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => Hub.DismissNotification(n.Id)">
                            Dismiss
                        </button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private IReadOnlyList<Notification> _notifications = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        _notifications = Hub.Notifications;
        _handler = () => InvokeAsync(() =>
        {
            _notifications = Hub.Notifications;
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    public void Dispose() => Hub.OnChange -= _handler;
}

@implements IDisposable
@inject NotificationHub Hub

<h5>Recent Unread</h5>

@if (!_recent.Any())
{
    <p class="text-muted">No unread notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _recent)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <span class="badge bg-@SeverityColor(n.Severity) me-1">@n.Severity</span>
                    <strong>@n.Title</strong>
                    <br /><small>@n.Message</small>
                </div>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Hub.DismissNotification(n.Id)">
                    Dismiss
                </button>
            </li>
        }
    </ul>
}

@code {
    private IReadOnlyList<Notification> _recent = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        Refresh();
        _handler = () => InvokeAsync(() =>
        {
            Refresh();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void Refresh()
    {
        _recent = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private static string SeverityColor(Severity s) => s switch
    {
        Severity.Critical => "danger",
        Severity.Warning => "warning",
        _ => "info"
    };

    public void Dispose() => Hub.OnChange -= _handler;
}

